using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateContext();
        TestHelpers.SeedStudents(_context);
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithPaginatedList()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
    }

    [Fact]
    public void Index_NameDesc_OrdersByLastNameDesc()
    {
        var result = _controller.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAsc()
    {
        var result = _controller.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName); // 2020
    }

    [Fact]
    public void Index_DateDesc_OrdersByEnrollmentDateDesc()
    {
        var result = _controller.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        // 2021 entries first (Alonso or Anand), 2020 last (Alexander)
        Assert.Equal("Alexander", model.Last().LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersOnFirstName()
    {
        var result = _controller.Index(null, null, "Meredith", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alonso", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_ResetsPage()
    {
        var result = _controller.Index(null, null, "Alex", 3);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alonso", null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        var result = _controller.Index("Date", null, "test", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("Date", viewResult.ViewData["CurrentSort"]);
        Assert.Equal("test", viewResult.ViewData["CurrentFilter"]);
    }

    [Fact]
    public void Index_SetsNameSortParm_EmptyWhenNoSort()
    {
        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
    }

    [Fact]
    public void Index_SetsNameSortParm_EmptyWhenNameDesc()
    {
        _controller.Index("name_desc", null, null, null);

        Assert.Equal("", _controller.ViewBag.NameSortParm);
    }

    [Fact]
    public void Index_SetsDateSortParm()
    {
        _controller.Index("Date", null, null, null);

        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudent()
    {
        var result = _controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    #endregion

    #region Create GET

    [Fact]
    public void Create_Get_ReturnsViewWithStudent()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    #endregion

    #region Create POST

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };

        var result = _controller.Create(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(4, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_DefaultEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidDateRange_AddsModelError()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(1752, 1, 1)
        };

        var result = _controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };

        var result = _controller.Create(student);

        Assert.IsType<ViewResult>(result);
        Assert.Equal(3, _context.Students.Count()); // no new student added
    }

    #endregion

    #region Edit GET

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsStudent()
    {
        var result = _controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    #endregion

    #region Edit POST

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Use a separate context to avoid tracking conflicts
        var dbName = Guid.NewGuid().ToString();
        using var seedContext = TestHelpers.CreateContext(dbName);
        TestHelpers.SeedStudents(seedContext);

        using var editContext = TestHelpers.CreateContext(dbName);
        using var controller = new StudentsController(editContext);

        var student = new Student
        {
            ID = 1,
            LastName = "Updated",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };

        var result = controller.Edit(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_DefaultEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            ID = 1,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = default(DateTime)
        };

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
    }

    #endregion

    #region Delete GET

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsStudent()
    {
        var result = _controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    #endregion

    #region DeleteConfirmed

    [Fact]
    public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
    {
        var result = _controller.DeleteConfirmed(1);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(2, _context.Students.Count());
    }

    #endregion
}

